+        {unit}
+      </text>
+      <rect x={x} y={y} width={width} height={height} rx={5} fill="#0F172A" stroke="#1E293B" strokeWidth={1} />
+      <rect x={x + 2} y={y + 2} width={fillW} height={height - 4} rx={3} fill={color} opacity={0.7}>
