+
+function determineHealth(s: HealthState): HealthLevel {
+  if (
+    s.poolAcquireP95Ms > 200 ||
+    s.wbqDepthPct > 80 ||
+    s.commitDepthPct > 80 ||
+    s.poolUtilPct > 90
+  ) return "red";
+
+  if (
+    s.poolAcquireP95Ms > 50 ||
+    s.wbqDepthPct > 50 ||
+    s.commitDepthPct > 50 ||
+    s.poolUtilPct > 70
