+    color: w.color,
+    id: w.id,
+  }));
+
+  // Buffer: middle area
+  const bufferDots = buffered.slice(-20).map((w, i) => ({
+    x: 230 + (i % 5) * 12,
+    y: 55 + Math.floor(i / 5) * 12,
+    color: w.color,
+    id: w.id,
+  }));
+
+  // Batches: right column
+  const batchBlocks = batches.slice(-8).map((b, i) => ({
+    x: 470,
