+      />
+      <text x={260} y={105} textAnchor="middle" fill="#475569" fontSize="7" fontFamily="monospace">
+        COALESCER
+      </text>
+
+      {/* Incoming dots */}
+      <AnimatePresence>
+        {incomingDots.map((d) => (
+          <motion.circle
+            key={`in-${d.id}`}
+            cx={d.x} cy={d.y} r={4}
+            fill={d.color}
+            initial={reducedMotion ? { opacity: 0.8 } : { opacity: 0, scale: 0 }}
