+        // Conflict!
+        files[step.fileIdx] = { editedBy: agent.name, color: agent.color, conflicted: true, overwritten: true };
+        events.unshift({ id: nextEventId++, text: `${step.description} -- OVERWRITES ${fileState.editedBy}!`, color: "#EF4444", bad: true });
+        conflicts++;
